proof fn phi_1_temp_pred_equality_intensional_bridge(p: TempPred<int>, q: TempPred<int>)
    requires
        p.entails(q),
        q.entails(p),
    ensures
        p == q,
{
    temp_pred_equality::<int>(p, q);
}

proof fn phi_2_mutual_entailment_derives_false_if_distinct(p: TempPred<int>, q: TempPred<int>)
    requires
        p.entails(q),
        q.entails(p),
        p !== q,
    ensures
        false,
{
    temp_pred_equality::<int>(p, q);
}

proof fn phi_3_tla_exists_equality_bridge(f: spec_fn(int, int) -> bool)
    ensures
        lift_state(|t: int| exists |a: int| #[trigger] f(a, t)) == tla_exists(|a: int| lift_state(|t: int| f(a, t))),
{
    tla_exists_equality::<int, int>(f);
}

proof fn phi_4_lift_state_closure_identity(p: StatePred<int>, q: StatePred<int>)
    requires
        forall |t: int| p(t) == q(t),
    ensures
        lift_state(p) == lift_state(q),
{
    temp_pred_equality::<int>(lift_state(p), lift_state(q));
}

proof fn phi_5_tla_exists_vacuous(f: spec_fn(int, int) -> bool)
    requires
        forall |a: int, t: int| !f(a, t),
    ensures
        lift_state(|t: int| exists |a: int| #[trigger] f(a, t)) == tla_exists(|a: int| lift_state(|t: int| f(a, t))),
{
    tla_exists_equality::<int, int>(f);
}
